10	`include "axi/typedef.svh"
11	
12	/// Infinite (Simulation-Only) Memory with AXI Slave Port
13	///
14	/// The memory array is named `mem`, and it is *not* initialized or reset.  This makes it possible to
15	/// load the memory of this module in simulation with an external `$readmem*` command, e.g.,
16	/// ```sv
17	/// axi_sim_mem #( ... ) i_sim_mem ( ... );
18	/// initial begin
19	///   $readmemh("file_with_memory_addrs_and_data.mem", i_sim_mem.mem);
20	///   $readmemh("file_with_memory_addrs_and_read_errors.mem", i_sim_mem.rerr);
21	///   $readmemh("file_with_memory_addrs_and_write_errors.mem", i_sim_mem.werr);
22	/// end
23	/// ```
24	/// `mem` is addressed (or indexed) byte-wise with `AddrWidth`-wide addresses.
25	///
26	/// This module does not support atomic operations (ATOPs).
27	module axi_sim_mem #(
28	  /// AXI Address Width
29	  parameter int unsigned AddrWidth = 32'd0,
30	  /// AXI Data Width
31	  parameter int unsigned DataWidth = 32'd0,
32	  /// AXI ID Width
33	  parameter int unsigned IdWidth = 32'd0,
34	  /// AXI User Width.
35	  parameter int unsigned UserWidth = 32'd0,
36	  /// Number of request ports
37	  parameter int unsigned NumPorts  = 32'd1,
38	  /// AXI4 request struct definition
39	  parameter type axi_req_t = logic,
40	  /// AXI4 response struct definition
41	  parameter type axi_rsp_t = logic,
42	  /// Warn on accesses to uninitialized bytes
43	  parameter bit WarnUninitialized = 1'b0,
44	  /// Default value for uninitialized memory (undefined, zeros, ones, random)
45	  parameter UninitializedData = "undefined",
46	  /// Clear error on access
47	  parameter bit ClearErrOnAccess = 1'b0,
48	  /// Application delay (measured after rising clock edge)
49	  parameter time ApplDelay = 0ps,
50	  /// Acquisition delay (measured after rising clock edge)
51	  parameter time AcqDelay = 0ps
52	) (
53	  /// Rising-edge clock
54	  input  logic clk_i,
55	  /// Active-low reset
56	  input  logic rst_ni,
57	  /// AXI4 request struct
58	  input  axi_req_t [NumPorts-1:0] axi_req_i,
59	  /// AXI4 response struct
60	  output axi_rsp_t [NumPorts-1:0] axi_rsp_o,
61	  /// Memory monitor write valid.  All `mon_w_*` outputs are only valid if this signal is high.
62	  /// A write to the memory is visible on the `mon_w_*` outputs in the clock cycle after it has
63	  /// happened.
64	  output logic [NumPorts-1:0]                mon_w_valid_o,
65	  /// Memory monitor write address
66	  output logic [NumPorts-1:0][AddrWidth-1:0] mon_w_addr_o,
67	  /// Memory monitor write data
68	  output logic [NumPorts-1:0][DataWidth-1:0] mon_w_data_o,
69	  /// Memory monitor write ID
70	  output logic [NumPorts-1:0][IdWidth-1:0]   mon_w_id_o,
71	  /// Memory monitor write user
72	  output logic [NumPorts-1:0][UserWidth-1:0] mon_w_user_o,
73	  /// Memory monitor write beat count
74	  output axi_pkg::len_t [NumPorts-1:0]       mon_w_beat_count_o,
75	  /// Memory monitor write last
76	  output logic [NumPorts-1:0]                mon_w_last_o,
77	  /// Memory monitor read valid.  All `mon_r_*` outputs are only valid if this signal is high.
78	  /// A read from the memory is visible on the `mon_w_*` outputs in the clock cycle after it has
79	  /// happened.
80	  output logic [NumPorts-1:0]                mon_r_valid_o,
81	  /// Memory monitor read address
82	  output logic [NumPorts-1:0][AddrWidth-1:0] mon_r_addr_o,
83	  /// Memory monitor read data
84	  output logic [NumPorts-1:0][DataWidth-1:0] mon_r_data_o,
85	  /// Memory monitor read ID
86	  output logic [NumPorts-1:0][IdWidth-1:0]   mon_r_id_o,
87	  /// Memory monitor read user
88	  output logic [NumPorts-1:0][UserWidth-1:0] mon_r_user_o,
89	  /// Memory monitor read beat count
90	  output axi_pkg::len_t [NumPorts-1:0]       mon_r_beat_count_o,
91	  /// Memory monitor read last
92	  output logic [NumPorts-1:0]                mon_r_last_o
93	);
94	
95	  localparam int unsigned StrbWidth = DataWidth / 8;
96	  typedef logic [AddrWidth-1:0] addr_t;
97	  typedef logic [DataWidth-1:0] data_t;
98	  typedef logic [IdWidth-1:0]   id_t;
99	  typedef logic [StrbWidth-1:0] strb_t;
100	  typedef logic [UserWidth-1:0] user_t;
101	  `AXI_TYPEDEF_AW_CHAN_T(aw_t, addr_t, id_t, user_t)
102	  `AXI_TYPEDEF_W_CHAN_T(w_t, data_t, strb_t, user_t)
103	  `AXI_TYPEDEF_B_CHAN_T(b_t, id_t, user_t)
104	  `AXI_TYPEDEF_AR_CHAN_T(ar_t, addr_t, id_t, user_t)
105	  `AXI_TYPEDEF_R_CHAN_T(r_t, data_t, id_t, user_t)
106	
107	  typedef struct packed {
108	    logic                 valid;
109	    logic [AddrWidth-1:0] addr;
110	    logic [DataWidth-1:0] data;
111	    logic [IdWidth-1:0]   id;
112	    logic [UserWidth-1:0] user;
113	    axi_pkg::len_t        beat_count;
114	    logic                 last;
115	  } monitor_t;
116	
117	  monitor_t [NumPorts-1:0] mon_w, mon_r;
118	  logic [7:0]     mem[addr_t];
119	  axi_pkg::resp_t rerr[addr_t] = '{default: 2'b0}; // default: 'axi_pkg::RESP_OKAY'
120	  axi_pkg::resp_t werr[addr_t] = '{default: 2'b0}; // default: 'axi_pkg::RESP_OKAY'
121	  // - Verilator cannot determine the type of 'axi_pkg::RESP_OKAY' in this context.
122	  //   The 'axi_pkg::RESP_OKAY' is expanded to 0 for Verilator compatibility.
123	
124	  // error happened in write burst
125	  axi_pkg::resp_t [NumPorts-1:0] error_happened = axi_pkg::RESP_OKAY;
126	
127	  for (genvar i = 0; i < NumPorts; i++) begin
128	    initial begin
129	      automatic ar_t ar_queue[$];
130	      automatic aw_t aw_queue[$];
131	      automatic b_t b_queue[$];
132	      automatic shortint unsigned r_cnt = 0, w_cnt = 0;
133	      axi_rsp_o[i] = '0;
134	      // Monitor interface
135	      mon_w[i] = '0;
136	      mon_r[i] = '0;
137	      wait (rst_ni);
138	      fork
139	        // AW
140	        forever begin
141	          @(posedge clk_i);
142	          #(ApplDelay);
143	          axi_rsp_o[i].aw_ready = 1'b1;
144	          #(AcqDelay - ApplDelay);
145	          if (axi_req_i[i].aw_valid) begin
146	            automatic aw_t aw = axi_req_i[i].aw;
147	            aw_queue.push_back(aw);
148	          end
149	        end
150	        // W
151	        forever begin
152	          @(posedge clk_i);
153	          #(ApplDelay);
154	          axi_rsp_o[i].w_ready = 1'b0;
155	          mon_w[i] = '0;
156	          if (aw_queue.size() != 0) begin
157	            axi_rsp_o[i].w_ready = 1'b1;
158	            #(AcqDelay - ApplDelay);
159	            if (axi_req_i[i].w_valid) begin
160	              automatic axi_pkg::burst_t burst = aw_queue[0].burst;
161	              automatic axi_pkg::len_t len = aw_queue[0].len;
162	              automatic axi_pkg::size_t size = aw_queue[0].size;
163	              automatic addr_t addr = axi_pkg::beat_addr(aw_queue[0].addr, size, len, burst,
164	                  w_cnt);
165	              mon_w[i].valid = 1'b1;
166	              mon_w[i].addr = addr;
167	              mon_w[i].data = axi_req_i[i].w.data;
168	              mon_w[i].id = aw_queue[0].id;
169	              mon_w[i].user = aw_queue[0].user;
170	              mon_w[i].beat_count = w_cnt;
171	              for (shortint unsigned
172	                  i_byte = axi_pkg::beat_lower_byte(aw_queue[0].addr, size, len, burst, StrbWidth, w_cnt);
173	                  i_byte <= axi_pkg::beat_upper_byte(aw_queue[0].addr, size, len, burst, StrbWidth, w_cnt);
174	                  i_byte++) begin
175	                if (axi_req_i[i].w.strb[i_byte]) begin
176	                  automatic addr_t byte_addr = (addr / StrbWidth) * StrbWidth + i_byte;
177	                  mem[byte_addr] = axi_req_i[i].w.data[i_byte*8+:8];
178	                  error_happened[i] = axi_pkg::resp_precedence(werr[byte_addr], error_happened[i]);
179	                  if (ClearErrOnAccess)
180	                    werr[byte_addr] = axi_pkg::RESP_OKAY;
181	                end
182	              end
183	              if (w_cnt == aw_queue[0].len) begin
184	                automatic b_t b_beat = '0;
185	                assert (axi_req_i[i].w.last) else $error("Expected last beat of W burst!");
186	                b_beat.id = aw_queue[0].id;
187	                b_beat.resp = error_happened[i];
188	                b_beat.user = aw_queue[0].user;
189	                b_queue.push_back(b_beat);
190	                w_cnt = 0;
191	                mon_w[i].last = 1'b1;
192	                error_happened[i] = axi_pkg::RESP_OKAY;
193	                void'(aw_queue.pop_front());
194	              end else begin
195	                assert (!axi_req_i[i].w.last) else $error("Did not expect last beat of W burst!");
196	                w_cnt++;
197	              end
198	            end
199	          end
200	        end
201	        // B
202	        forever begin
203	          @(posedge clk_i);
204	          #(ApplDelay);
205	          axi_rsp_o[i].b_valid = 1'b0;
206	          if (b_queue.size() != 0) begin
207	            axi_rsp_o[i].b = b_queue[0];
208	            axi_rsp_o[i].b_valid = 1'b1;
209	            #(AcqDelay - ApplDelay);
210	            if (axi_req_i[i].b_ready) begin
211	              void'(b_queue.pop_front());
212	            end
213	          end
214	        end
215	        // AR
216	        forever begin
217	          @(posedge clk_i);
218	          #(ApplDelay);
219	          axi_rsp_o[i].ar_ready = 1'b1;
220	          #(AcqDelay - ApplDelay);
221	          if (axi_req_i[i].ar_valid) begin
222	            automatic ar_t ar = axi_req_i[i].ar;
223	            ar_queue.push_back(ar);
224	          end
225	        end
226	        // R
227	        forever begin
228	          @(posedge clk_i);
229	          #(ApplDelay);
230	          axi_rsp_o[i].r_valid = 1'b0;
231	          mon_r[i] = '0;
232	          if (ar_queue.size() != 0) begin
233	            automatic axi_pkg::burst_t burst = ar_queue[0].burst;
234	            automatic axi_pkg::len_t len = ar_queue[0].len;
235	            automatic axi_pkg::size_t size = ar_queue[0].size;
236	            automatic addr_t addr = axi_pkg::beat_addr(ar_queue[0].addr, size, len, burst, r_cnt);
237	            automatic r_t r_beat = '0;
238	            automatic data_t r_data = 'x; // compatibility reasons
239	            r_beat.data = 'x;
240	            r_beat.id = ar_queue[0].id;
241	            r_beat.resp = axi_pkg::RESP_OKAY;
242	            r_beat.user = ar_queue[0].user;
243	            for (shortint unsigned
244	                i_byte = axi_pkg::beat_lower_byte(ar_queue[0].addr, size, len, burst, StrbWidth, r_cnt);
245	                i_byte <= axi_pkg::beat_upper_byte(ar_queue[0].addr, size, len, burst, StrbWidth, r_cnt);
246	                i_byte++) begin
247	              automatic addr_t byte_addr = (addr / StrbWidth) * StrbWidth + i_byte;
248	              if (!mem.exists(byte_addr)) begin
249	                if (WarnUninitialized) begin
250	                  $warning("Access to non-initialized byte at address 0x%016x by ID 0x%x.", byte_addr,
251	                      r_beat.id);
252	                end
253	                case (UninitializedData)
254	                  "random":
255	                    r_data[i_byte*8+:8] = $urandom;
256	                  "ones":
257	                    r_data[i_byte*8+:8] = '1;
258	                  "zeros":
259	                    r_data[i_byte*8+:8] = '0;
260	                  default: 
261	                    r_data[i_byte*8+:8] = 'x;
262	                endcase
263	              end else begin
264	                r_data[i_byte*8+:8] = mem[byte_addr];
265	              end
266	              r_beat.resp = axi_pkg::resp_precedence(rerr[byte_addr], r_beat.resp);
267	              if (ClearErrOnAccess & axi_req_i[i].r_ready) begin
268	                rerr[byte_addr] = axi_pkg::RESP_OKAY;
269	              end
270	            end
271	            r_beat.data = r_data;
272	            if (r_cnt == ar_queue[0].len) begin
273	              r_beat.last = 1'b1;
274	              mon_r[i].last = 1'b1;
275	            end
276	            axi_rsp_o[i].r = r_beat;
277	            axi_rsp_o[i].r_valid = 1'b1;
278	            mon_r[i].valid = 1'b1;
279	            mon_r[i].addr = addr;
280	            mon_r[i].data = r_beat.data;
281	            mon_r[i].id = r_beat.id;
282	            mon_r[i].user = ar_queue[0].user;
283	            mon_r[i].beat_count = r_cnt;
284	            #(AcqDelay - ApplDelay);
285	            while (!axi_req_i[i].r_ready) begin
286	              @(posedge clk_i);
287	              #(AcqDelay);
288	              mon_r[i] = '0;
289	            end
290	            if (r_beat.last) begin
291	              r_cnt = 0;
292	              void'(ar_queue.pop_front());
293	            end else begin
294	              r_cnt++;
295	            end
296	          end
297	        end
298	      join
299	    end
300	
301	    // Assign the monitor output in the next clock cycle.  Rationale: We only know whether we are
302	    // writing until after `AcqDelay`.  This means we could only provide the monitoring output for
303	    // writes after `AcqDelay` in the same cycle, which is incompatible with ATI timing.  Thus, we
304	    // provide the monitoring output for writes (and for uniformity also for reads) in the next clock
305	    // cycle.
306	    initial begin
307	      mon_w_valid_o[i] = '0;
308	      mon_w_addr_o[i] = '0;
309	      mon_w_data_o[i] = '0;
310	      mon_w_id_o[i] = '0;
311	      mon_w_user_o[i] = '0;
312	      mon_w_beat_count_o[i] = '0;
313	      mon_w_last_o[i] = '0;
314	      mon_r_valid_o[i] = '0;
315	      mon_r_addr_o[i] = '0;
316	      mon_r_data_o[i] = '0;
317	      mon_r_id_o[i] = '0;
318	      mon_r_user_o[i] = '0;
319	      mon_r_beat_count_o[i] = '0;
320	      mon_r_last_o[i] = '0;
321	      wait (rst_ni);
322	      forever begin
323	        @(posedge clk_i);
324	        mon_w_valid_o[i] <= #(ApplDelay) mon_w[i].valid;
325	        mon_w_addr_o[i] <= #(ApplDelay) mon_w[i].addr;
326	        mon_w_data_o[i] <= #(ApplDelay) mon_w[i].data;
327	        mon_w_id_o[i] <= #(ApplDelay) mon_w[i].id;
328	        mon_w_user_o[i] <= #(ApplDelay) mon_w[i].user;
329	        mon_w_beat_count_o[i] <= #(ApplDelay) mon_w[i].beat_count;
330	        mon_w_last_o[i] <= #(ApplDelay) mon_w[i].last;
331	        mon_r_valid_o[i] <= #(ApplDelay) mon_r[i].valid;
332	        mon_r_addr_o[i] <= #(ApplDelay) mon_r[i].addr;
333	        mon_r_data_o[i] <= #(ApplDelay) mon_r[i].data;
334	        mon_r_id_o[i] <= #(ApplDelay) mon_r[i].id;
335	        mon_r_user_o[i] <= #(ApplDelay) mon_r[i].user;
336	        mon_r_beat_count_o[i] <= #(ApplDelay) mon_r[i].beat_count;
337	        mon_r_last_o[i] <= #(ApplDelay) mon_r[i].last;
338	      end
339	    end
340	  end
341	
342	  // Parameter Assertions
343	  initial begin
344	    assert (AddrWidth != 0) else $fatal(1, "AddrWidth must be non-zero!");
345	    assert (DataWidth != 0) else $fatal(1, "DataWidth must be non-zero!");
346	    assert (IdWidth != 0) else $fatal(1, "IdWidth must be non-zero!");
347	    assert (UserWidth != 0) else $fatal(1, "UserWidth must be non-zero!");
348	  end
349	
350	endmodule
351	
352	
353	`include "axi/assign.svh"
354	
355	/// Interface variant of [`axi_sim_mem`](module.axi_sim_mem).
356	///
357	/// See the documentation of the main module for the definition of ports and parameters.
358	module axi_sim_mem_intf #(
359	  parameter int unsigned AXI_ADDR_WIDTH = 32'd0,
360	  parameter int unsigned AXI_DATA_WIDTH = 32'd0,
361	  parameter int unsigned AXI_ID_WIDTH = 32'd0,
362	  parameter int unsigned AXI_USER_WIDTH = 32'd0,
363	  parameter bit WARN_UNINITIALIZED = 1'b0,
364	  parameter UNINITIALIZED_DATA = "undefined",
365	  parameter bit ClearErrOnAccess = 1'b0,
366	  parameter time APPL_DELAY = 0ps,
367	  parameter time ACQ_DELAY = 0ps
368	) (
369	  input  logic                      clk_i,
370	  input  logic                      rst_ni,
371	  AXI_BUS.Slave                     axi_slv,
372	  output logic                      mon_w_valid_o,
373	  output logic [AXI_ADDR_WIDTH-1:0] mon_w_addr_o,
374	  output logic [AXI_DATA_WIDTH-1:0] mon_w_data_o,
375	  output logic [AXI_ID_WIDTH-1:0]   mon_w_id_o,
376	  output logic [AXI_USER_WIDTH-1:0] mon_w_user_o,
377	  output axi_pkg::len_t             mon_w_beat_count_o,
378	  output logic                      mon_w_last_o,
379	  output logic                      mon_r_valid_o,
380	  output logic [AXI_ADDR_WIDTH-1:0] mon_r_addr_o,
381	  output logic [AXI_DATA_WIDTH-1:0] mon_r_data_o,
382	  output logic [AXI_ID_WIDTH-1:0]   mon_r_id_o,
383	  output logic [AXI_USER_WIDTH-1:0] mon_r_user_o,
384	  output axi_pkg::len_t             mon_r_beat_count_o,
385	  output logic                      mon_r_last_o
386	);
387	  
388	  typedef logic [AXI_ADDR_WIDTH-1:0]   axi_addr_t;
389	  typedef logic [AXI_DATA_WIDTH-1:0]   axi_data_t;
390	  typedef logic [AXI_ID_WIDTH-1:0]     axi_id_t;
391	  typedef logic [AXI_DATA_WIDTH/8-1:0] axi_strb_t;
392	  typedef logic [AXI_USER_WIDTH-1:0]   axi_user_t;
393	  `AXI_TYPEDEF_ALL(axi, axi_addr_t, axi_id_t, axi_data_t, axi_strb_t, axi_user_t)
394	
395	  axi_req_t  axi_req;
396	  axi_resp_t axi_rsp;
397	
398	  `AXI_ASSIGN_TO_REQ(axi_req, axi_slv)
399	  `AXI_ASSIGN_FROM_RESP(axi_slv, axi_rsp)
400	
401	  axi_sim_mem #(
402	    .AddrWidth          (AXI_ADDR_WIDTH),
403	    .DataWidth          (AXI_DATA_WIDTH),
404	    .IdWidth            (AXI_ID_WIDTH),
405	    .UserWidth          (AXI_USER_WIDTH),
406	    .axi_req_t          (axi_req_t),
407	    .axi_rsp_t          (axi_resp_t),
408	    .WarnUninitialized  (WARN_UNINITIALIZED),
409	    .UninitializedData  (UNINITIALIZED_DATA),
410	    .ClearErrOnAccess   (ClearErrOnAccess),
411	    .ApplDelay          (APPL_DELAY),
412	    .AcqDelay           (ACQ_DELAY)
413	  ) i_sim_mem (
414	    .clk_i,
415	    .rst_ni,
416	    .axi_req_i (axi_req),
417	    .axi_rsp_o (axi_rsp),
418	    .mon_w_valid_o,
419	    .mon_w_addr_o,
420	    .mon_w_data_o,
421	    .mon_w_id_o,
422	    .mon_w_user_o,
423	    .mon_w_beat_count_o,
424	    .mon_w_last_o,
425	    .mon_r_valid_o,
426	    .mon_r_addr_o,
427	    .mon_r_data_o,
428	    .mon_r_id_o,
429	    .mon_r_user_o,
430	    .mon_r_beat_count_o,
431	    .mon_r_last_o
432	  );
433	
434	endmodule
