436	/// Mutliport interface variant of [`axi_sim_mem`](module.axi_sim_mem).
437	///
438	/// See the documentation of the main module for the definition of ports and parameters.
439	module axi_sim_mem_multiport_intf #(
440	  parameter int unsigned AXI_ADDR_WIDTH = 32'd0,
441	  parameter int unsigned AXI_DATA_WIDTH = 32'd0,
442	  parameter int unsigned AXI_ID_WIDTH = 32'd0,
443	  parameter int unsigned AXI_USER_WIDTH = 32'd0,
444	  parameter int unsigned NUM_PORTS = 32'd1,
445	  parameter bit WARN_UNINITIALIZED = 1'b0,
446	  parameter UNINITIALIZED_DATA = "undefined",
447	  parameter bit ClearErrOnAccess = 1'b0,
448	  parameter time APPL_DELAY = 0ps,
449	  parameter time ACQ_DELAY = 0ps
450	) (
451	  input  logic                      clk_i,
452	  input  logic                      rst_ni,
453	  AXI_BUS.Slave                     axi_slv[NUM_PORTS],
454	  output logic [NUM_PORTS-1:0]                     mon_w_valid_o,
455	  output logic [NUM_PORTS-1:0][AXI_ADDR_WIDTH-1:0] mon_w_addr_o,
456	  output logic [NUM_PORTS-1:0][AXI_DATA_WIDTH-1:0] mon_w_data_o,
457	  output logic [NUM_PORTS-1:0][AXI_ID_WIDTH-1:0]   mon_w_id_o,
458	  output logic [NUM_PORTS-1:0][AXI_USER_WIDTH-1:0] mon_w_user_o,
459	  output axi_pkg::len_t [NUM_PORTS-1:0]            mon_w_beat_count_o,
460	  output logic [NUM_PORTS-1:0]                     mon_w_last_o,
461	  output logic [NUM_PORTS-1:0]                     mon_r_valid_o,
462	  output logic [NUM_PORTS-1:0][AXI_ADDR_WIDTH-1:0] mon_r_addr_o,
463	  output logic [NUM_PORTS-1:0][AXI_DATA_WIDTH-1:0] mon_r_data_o,
464	  output logic [NUM_PORTS-1:0][AXI_ID_WIDTH-1:0]   mon_r_id_o,
465	  output logic [NUM_PORTS-1:0][AXI_USER_WIDTH-1:0] mon_r_user_o,
466	  output axi_pkg::len_t [NUM_PORTS-1:0]            mon_r_beat_count_o,
467	  output logic [NUM_PORTS-1:0]                     mon_r_last_o
468	);
469	
470	  typedef logic [AXI_ADDR_WIDTH-1:0]   axi_addr_t;
471	  typedef logic [AXI_DATA_WIDTH-1:0]   axi_data_t;
472	  typedef logic [AXI_ID_WIDTH-1:0]     axi_id_t;
473	  typedef logic [AXI_DATA_WIDTH/8-1:0] axi_strb_t;
474	  typedef logic [AXI_USER_WIDTH-1:0]   axi_user_t;
475	  `AXI_TYPEDEF_ALL(axi, axi_addr_t, axi_id_t, axi_data_t, axi_strb_t, axi_user_t)
476	
477	  axi_req_t  [NUM_PORTS-1:0] axi_req;
478	  axi_resp_t [NUM_PORTS-1:0] axi_rsp;
479	
480	  for (genvar i = 0; i < NUM_PORTS; i++) begin
481	    `AXI_ASSIGN_TO_REQ(axi_req[i], axi_slv[i])
482	    `AXI_ASSIGN_FROM_RESP(axi_slv[i], axi_rsp[i])
483	  end
484	
485	  axi_sim_mem #(
486	    .AddrWidth          (AXI_ADDR_WIDTH),
487	    .DataWidth          (AXI_DATA_WIDTH),
488	    .IdWidth            (AXI_ID_WIDTH),
489	    .UserWidth          (AXI_USER_WIDTH),
490	    .NumPorts           (NUM_PORTS),
491	    .axi_req_t          (axi_req_t),
492	    .axi_rsp_t          (axi_resp_t),
493	    .WarnUninitialized  (WARN_UNINITIALIZED),
494	    .UninitializedData  (UNINITIALIZED_DATA),
495	    .ClearErrOnAccess   (ClearErrOnAccess),
496	    .ApplDelay          (APPL_DELAY),
497	    .AcqDelay           (ACQ_DELAY)
498	  ) i_sim_mem (
499	    .clk_i,
500	    .rst_ni,
501	    .axi_req_i (axi_req),
502	    .axi_rsp_o (axi_rsp),
503	    .mon_w_valid_o,
504	    .mon_w_addr_o,
505	    .mon_w_data_o,
506	    .mon_w_id_o,
507	    .mon_w_user_o,
508	    .mon_w_beat_count_o,
509	    .mon_w_last_o,
510	    .mon_r_valid_o,
511	    .mon_r_addr_o,
512	    .mon_r_data_o,
513	    .mon_r_id_o,
514	    .mon_r_user_o,
515	    .mon_r_beat_count_o,
516	    .mon_r_last_o
517	  );
518	
